import { Schema, model, Types } from 'mongoose';

interface Group {
  id: Types.ObjectId;
  name: string;
  description: string;
  adminId: Types.ObjectId;
  members: Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Types.ObjectId, required: true },
  members: [{ type: Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model<Group>('Group', groupSchema);

import { Schema, model, Types } from 'mongoose';

interface Recurrence {
  type: 'daily' | 'weekly' | 'custom';
  daysOfWeek?: number[];
  time: string;
}

interface Task {
  id: Types.ObjectId;
  groupId: Types.ObjectId;
  title: string;
  description: string;
  assignees: Types.ObjectId[];
  rotationIndex: number;
  unavailableMembers?: Types.ObjectId[];
  recurrence: Recurrence;
  status: 'active' | 'paused';
}

const recurrenceSchema = new Schema<Recurrence>({
  type: { type: String, enum: ['daily', 'weekly', 'custom'], required: true },
  daysOfWeek: { type: [Number], default: void 0 },
  time: { type: String, required: true }
});

const taskSchema = new Schema<Task>({
  groupId: { type: Types.ObjectId, ref: 'Group', required: true },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: [{ type: Types.ObjectId, ref: 'User', required: true }],
  rotationIndex: { type: Number, default: 0 },
  unavailableMembers: [{ type: Types.ObjectId, ref: 'User' }],
  recurrence: { type: recurrenceSchema, required: true },
  status: { type: String, enum: ['active', 'paused'], default: 'active' }
});

export const TaskModel = model<Task>('Task', taskSchema);
